import json
import logging
import boto3

# Define IAM role with S3 read/write, SNS publish, CloudWatch logging permissions
# IAM Role: arn:aws:iam::123456789012:role/lambda_image_processing_role

def lambda_handler(event, context):
    # Get S3 event details
    bucket = event['Records'][0]['s3']['bucket']['name']
    key = event['Records'][0]['s3']['object']['key']

    # Create S3 client
    s3_client = boto3.client('s3')

    # Read image from S3
    image_data = s3_client.get_object(Bucket=bucket, Key=key)['Body'].read()

    # Process image here (e.g., resize, convert to grayscale)

    # Write results to S3
    s3_client.put_object(Bucket=bucket, Key='processed_' + key, Body=image_data)

    # Send notification via SNS
    sns_client = boto3.client('sns')
    sns_client.publish(TopicArn='arn:aws:sns:us-east-1:123456789012:image_processed_topic', Message='Image processed successfully')

    # Log to CloudWatch
    logger = logging.getLogger()
    logger.setLevel(logging.INFO)
    logger.info('Image processed successfully.')